changeSet.sql:

ALTER TABLE tag ADD COLUMN fulltext_search tsvector;

CREATE OR REPLACE FUNCTION tag_change_trigger()
 RETURNS TRIGGER AS
    $tagchange$
      BEGIN
       NEW.fulltext_search :=
         TO_TSVECTOR('english_nostop', unaccent(COALESCE(NEW.name,'')));
        RETURN NEW;
      END;
    $tagchange$
LANGUAGE plpgsql;

CREATE TRIGGER tag_fulltext_update
  BEFORE INSERT OR UPDATE ON tag
  FOR EACH ROW EXECUTE PROCEDURE tag_change_trigger();
